import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import { Mail, Lock, ArrowRight, ShieldCheck } from 'lucide-react';

export default function Login() {
  const navigate = useNavigate();
  const [email, setEmail] = useState('gauryparvathy444@gmail.com');
  const [password, setPassword] = useState('');

  const handleLogin = (e) => {
    e.preventDefault();
    if (password.length > 0) {
      navigate('/dashboard');
    } else {
      alert("Please enter your password to continue.");
    }
  };

  const handleForgot = () => {
    alert("Reset link sent to: " + email);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
      <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="max-w-md w-full bg-white p-10 rounded-[40px] shadow-2xl border border-white">
        <div className="flex flex-col items-center mb-10 text-center">
          <div className="w-16 h-16 bg-teal-500 rounded-2xl flex items-center justify-center shadow-lg shadow-teal-500/20 mb-6">
            <ShieldCheck className="text-white" size={32} />
          </div>
          <h1 className="text-3xl font-black text-slate-900">Welcome Back</h1>
          <p className="text-slate-500 font-medium mt-2">Access your local barter hub</p>
        </div>

        <form onSubmit={handleLogin} className="space-y-6">
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Email</label>
            <div className="relative">
              <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input type="email" value={email} readOnly className="w-full pl-12 pr-4 py-4 bg-slate-50 rounded-2xl font-medium outline-none" />
            </div>
          </div>

          <div className="space-y-2">
            <div className="flex justify-between items-center px-1">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Password</label>
              <button type="button" onClick={handleForgot} className="text-[10px] font-black text-teal-600 hover:text-teal-700 uppercase tracking-widest">Forgot Password?</button>
            </div>
            <div className="relative">
              <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input type="password" placeholder="••••••••" value={password} onChange={(e) => setPassword(e.target.value)} className="w-full pl-12 pr-4 py-4 bg-slate-50 border-none rounded-2xl focus:ring-2 ring-teal-500 outline-none font-medium transition-all" />
            </div>
          </div>

          <button type="submit" className="w-full bg-teal-600 hover:bg-teal-700 text-white py-4 rounded-2xl font-bold flex items-center justify-center gap-2 transition-all active:scale-[0.98] shadow-lg shadow-teal-600/20">
            Login to Wertech <ArrowRight size={20} />
          </button>
        </form>

        <p className="text-center mt-10 text-sm font-medium text-slate-500">
          New to the community? <Link to="/register" className="text-teal-600 font-bold hover:underline">Create an Account</Link>
        </p>
      </motion.div>
    </div>
  );
}
